import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from '../api/axios';

const Dashboard = () => {
  const navigate = useNavigate();
  const [syllabus, setSyllabus] = useState('');
  const [targetDate, setTargetDate] = useState('');
  const [loading, setLoading] = useState(false);

  const generateSchedule = async () => {
    if (!syllabus || !targetDate) return alert("Fill all fields");
    setLoading(true);
    try {
      // Sending to backend to create the plan and tasks
      await axios.post('/plan/create', { syllabus, examDate: targetDate });
      navigate('/planPage');
    } catch (err) {
      console.error(err);
      alert("Error generating plan");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: '50px', maxWidth: '500px', margin: '0 auto' }}>
      <h1>Create Study Plan</h1>
      <input type="date" value={targetDate} onChange={(e) => setTargetDate(e.target.value)} style={{ display: 'block', width: '100%', marginBottom: '10px', padding: '10px' }} />
      <textarea placeholder="Enter topics separated by commas" value={syllabus} onChange={(e) => setSyllabus(e.target.value)} style={{ display: 'block', width: '100%', height: '100px', marginBottom: '10px', padding: '10px' }} />
      <button onClick={generateSchedule} disabled={loading} style={{ width: '100%', padding: '10px', background: '#3498db', color: '#fff', border: 'none', cursor: 'pointer' }}>
        {loading ? 'Generating...' : 'Generate Plan'}
      </button>
    </div>
  );
};

export default Dashboard;
